<article class="index_simple lazy_load news  ">
    <section class="body">
        <div class="content_wrap">
                <div class="main_content">
                        <header class="header">
                                <h1>eDziecko.pl - Ciąża, Poród,  Zdrowie i Wychowanie Dzieci</h1>
                                </header>
                        <ul class="list_tiles">
            <li class="entry">
                    <a href="https://www.edziecko.pl/rodzice/7,79361,32320537,matka-6-latka-chce-kupic-dziecku-smycz-ale-moj-partner-sie.html" title="Matka 6-latka: Chcę kupić dziecku smycz, ale mój partner się nie zgadza. Twierdzi, że to dehumanizuje">
                            <figure class="imgw">
                                <img src="https://bi.im-g.pl/im/15/d2/1e/z32321045II,Smycz.jpg" fetchpriority="high" alt="Matka 6-latka: Chcę kupić dziecku smycz, ale mój partner się nie zgadza. Twierdzi, że to dehumanizuje" />
                                        </figure>
